/* ============================================================
   Kiosk Client — main interactive app
   ============================================================ */
const { useState, useEffect, useRef, useCallback } = React;

function useCountdown(start, running) {
  const [s, setS] = useState(start);
  useEffect(() => {
    if (!running) return;
    const id = setInterval(() => setS((v) => (v > 0 ? v - 1 : 0)), 1000);
    return () => clearInterval(id);
  }, [running]);
  const reset = useCallback(() => setS(start), [start]);
  const mm = String(Math.floor(s / 60)).padStart(2, "0");
  const ss = String(s % 60).padStart(2, "0");
  return [`${mm}:${ss}`, s, reset];
}

function App({ externalLang, onLangChange, orientation }) {
  const [lang, setLang] = useState(externalLang || "vi");
  const isLandscape = orientation === "landscape";
  const handleLangChange = (l) => { setLang(l); if (onLangChange) onLangChange(l); };
  const t = useCallback((o) => (o ? o[lang] : ""), [lang]);
  const STEPS = window.KIOSK.STEPS;
  const HELP = window.KIOSK.HELP;

  const [idx, setIdx] = useState(0);
  const step = STEPS[idx];
  const [phase, setPhase] = useState("engine"); // engine | action | acting
  const [progress, setProgress] = useState(0);
  const [cursor, setCursor] = useState({ x: 50, y: 35, click: false, show: false });

  // ---- Virtual keyboard state ----
  const [kb, setKb] = useState({ open: false, mode: "text", label: "", value: "", onConfirm: null });
  const openKb = useCallback((mode, label, initial, onConfirm) => {
    setKb({ open: true, mode, label, value: initial || "", onConfirm });
  }, []);
  const closeKb = useCallback(() => setKb((k) => ({ ...k, open: false })), []);
  const [cardRead, setCardRead] = useState(false);
  const [scanned, setScanned] = useState(false);
  const [textScale, setTextScale] = useState(1);

  const [msgs, setMsgs] = useState([]);
  const [typing, setTyping] = useState(false);
  const [draft, setDraft] = useState("");
  const chatRef = useRef(null);
  const timers = useRef([]);

  const [time, secsLeft, resetTime] = useCountdown(15 * 60, true);
  const lowTime = secsLeft <= 120;

  const clearTimers = () => { timers.current.forEach(clearTimeout); timers.current = []; };
  const after = (ms, fn) => { const id = setTimeout(fn, ms); timers.current.push(id); };

  // AI message helper
  const pushAI = useCallback((text) => {
    setTyping(true);
    after(700, () => { setTyping(false); setMsgs((m) => [...m, { role: "ai", text }]); });
  }, []);

  // ---- drive each step's engine animation on enter ----
  useEffect(() => {
    clearTimers();
    setPhase("engine");
    setProgress(0);
    // cursor travels to the hot zone
    setCursor({ x: 50, y: 80, click: false, show: step.mode === "auto" });
    after(250, () => setCursor((c) => ({ ...c, show: step.mode === "auto", x: step.hot.x, y: step.hot.y })));
    // loading bar
    after(150, () => setProgress(70));
    after(900, () => setProgress(100));
    // click pulse for auto steps
    if (step.mode === "auto") after(1150, () => setCursor((c) => ({ ...c, click: true })));
    after(1350, () => setCursor((c) => ({ ...c, click: false })));
    // AI intro for the step
    pushAI(t(step.ai));
    // move to action phase
    after(1500, () => { setPhase("action"); setProgress(0); });
    return clearTimers;
    // eslint-disable-next-line
  }, [idx, lang]);

  useEffect(() => { if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight; }, [msgs, typing]);

  const goNext = () => {
    if (idx < STEPS.length - 1) setIdx(idx + 1);
  };

  const restart = () => {
    clearTimers();
    setMsgs([]); setCardRead(false); setScanned(false); resetTime();
    setIdx(0);
  };

  // primary CTA behaviour per step
  const doPrimary = () => {
    if (phase !== "action") return;
    if (idx === STEPS.length - 1) { restart(); return; }
    if (step.mode === "card") {
      setPhase("acting"); setCardRead(true);
      pushAI(t({ vi: "Đã đọc thẻ thành công. Cảm ơn bạn!", en: "Card read successfully. Thank you!" }));
      after(1100, goNext);
    } else if (step.mode === "scan") {
      setPhase("acting"); setScanned(true);
      pushAI(t({ vi: "Đã quét và tải lên giấy tờ của bạn.", en: "Your document has been scanned and uploaded." }));
      after(1100, goNext);
    } else {
      goNext();
    }
  };

  const ctaLabel = () => {
    if (idx === STEPS.length - 1) return t({ vi: "In biên nhận & Kết thúc", en: "Print receipt & Finish" });
    if (phase !== "action") return t({ vi: "Đang xử lý…", en: "Processing…" });
    switch (step.mode) {
      case "card": return t({ vi: "Đặt thẻ CCCD lên đầu đọc", en: "Place ID card on reader" });
      case "scan": return t({ vi: "Quét giấy tờ", en: "Scan document" });
      case "confirm": return t({ vi: "Xác nhận đúng", en: "Confirm — it's correct" });
      default: return t({ vi: "Tiếp tục", en: "Continue" });
    }
  };
  const ctaIcon = () => (idx === STEPS.length - 1 ? "printer" : step.mode === "card" ? "idcard" : step.mode === "scan" ? "scan" : step.mode === "confirm" ? "check" : "arrow");

  // ---- AI quick help ----
  const askHelp = (h) => {
    setMsgs((m) => [...m, { role: "user", text: t(h.q) }]);
    const ans = h.a ? t(h.a) : t(step.ai);
    pushAI(ans);
  };
  const sendDraft = () => {
    if (!draft.trim()) return;
    setMsgs((m) => [...m, { role: "user", text: draft.trim() }]);
    setDraft("");
    pushAI(t({ vi: "Tôi hiểu rồi. Bạn cứ làm theo bước đang hiện trên màn hình — tôi luôn ở đây nếu bạn cần. Bạn cũng có thể chạm “Gọi cán bộ” bất cứ lúc nào.", en: "Got it. Just follow the step shown on screen — I'm right here if you need me. You can also tap “Call staff” anytime." }));
  };

  const engineRunning = phase === "engine" || phase === "acting";

  return (
    <div className="kiosk-screen" style={{ fontSize: `calc(1rem * ${textScale})` }}>
      {/* ============ HEADER ============ */}
      <header className="k-header">
        <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
          <div className="k-logo"><Icon name="building" size={28} style={{ color: "#fff" }} /></div>
          <div style={{ lineHeight: 1.18 }}>
            <div className="font-display" style={{ fontSize: "clamp(18px,2.4vw,30px)", fontWeight: 700, letterSpacing: "-.02em", color: "var(--ink)" }}>{t({ vi: "Kiosk Dịch vụ công", en: "Public Service Kiosk" })}</div>
            <div style={{ fontSize: "clamp(12px,1.5vw,17px)", color: "var(--ink-3)", fontWeight: 500 }}>{t({ vi: "UBND Phường Cửa Nam · Quầy 03", en: "Cua Nam Ward Office · Bay 03" })}</div>
          </div>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <StatusChip icon="monitor" label={t({ vi: "Thiết bị", en: "Device" })} value={t({ vi: "Hoạt động", en: "Online" })} tone="ok" />
          <StatusChip icon="wifi" label={t({ vi: "Kết nối", en: "Internet" })} value={t({ vi: "Ổn định", en: "Stable" })} tone="ok" />
          <div className={"k-timer" + (lowTime ? " low" : "")}>
            <Icon name="clock" size={26} style={{ color: lowTime ? "var(--err)" : "var(--primary)" }} />
            <div style={{ lineHeight: 1.05 }}>
              <div style={{ fontSize: "clamp(11px,1.4vw,16px)", color: "var(--ink-3)", fontWeight: 600, letterSpacing: ".02em" }}>{t({ vi: "PHIÊN CÒN", en: "SESSION" })}</div>
              <div className="font-display" style={{ fontSize: "clamp(22px,2.8vw,36px)", fontWeight: 700, color: lowTime ? "var(--err)" : "var(--ink)", fontVariantNumeric: "tabular-nums", letterSpacing: "-.01em" }}>{time}</div>
            </div>
          </div>
          {/* lang + text size */}
          <div className="k-toolbtns">
            <button className="press k-toolbtn" onClick={() => setTextScale((s) => Math.max(0.9, +(s - 0.1).toFixed(2)))} aria-label="Smaller text">A−</button>
            <button className="press k-toolbtn" onClick={() => setTextScale((s) => Math.min(1.3, +(s + 0.1).toFixed(2)))} aria-label="Larger text" style={{ fontSize: 22 }}>A+</button>
            <button className="press k-toolbtn lang" onClick={() => handleLangChange(lang === "vi" ? "en" : "vi")} aria-label="Language">
              <Icon name="globe" size={20} style={{ color: "var(--primary)" }} />{lang === "vi" ? "VI" : "EN"}
            </button>
          </div>
        </div>
      </header>

      {/* ============ MAIN ============ */}
      <main className="k-main">
        {/* Browser Automation View */}
        <section className="k-browser">
          <div className="k-urlbar">
            <span className="k-dots"><i/><i/><i/></span>
            <div className="k-url"><Icon name="lock" size={15} style={{ color: "var(--ok)" }} /> https://dichvucong.gov.vn</div>
            <div className={"k-engine-badge" + (engineRunning ? " on" : "")}>
              <span className="k-engine-dot" /> {engineRunning ? t({ vi: "Tự động hoá đang chạy", en: "Automation running" }) : t({ vi: "Sẵn sàng", en: "Ready" })}
            </div>
          </div>
          <div className="k-viewport">
            {engineRunning && <div className="k-loadbar" style={{ width: progress + "%" }} />}
            <Scene scene={step.scene} t={t} cardRead={cardRead} scanned={scanned} />
            {/* highlight ring on target */}
            {step.mode === "auto" && (phase === "engine") && (
              <div className="k-hot" style={{ left: step.hot.x + "%", top: step.hot.y + "%", width: step.hot.w + "%", height: step.hot.h + "%" }} />
            )}
            {/* automation cursor */}
            {cursor.show && (
              <div className="k-cursor" style={{ left: cursor.x + "%", top: cursor.y + "%" }}>
                <svg viewBox="0 0 24 24" width="34" height="34"><path d="M5 3l15 9-6.5 1.8L10 21z" fill="#fff" stroke="#211f1d" strokeWidth="1.4" strokeLinejoin="round"/></svg>
                {cursor.click && <span className="k-ripple" />}
              </div>
            )}
            {/* step toast */}
            <div className="k-toast">
              <span className={"k-toast-spin" + (engineRunning ? " spin" : "")}><Icon name={engineRunning ? "refresh" : "checkCircle"} size={18} style={{ color: engineRunning ? "var(--primary)" : "var(--ok)" }} /></span>
              {t(step.status)}
            </div>
          </div>
        </section>

        {/* AI Assistant — full-width bottom, 2-col inside */}
        <section className="k-ai">
          {/* header */}
          <div className="k-ai-head">
            <div className="k-ai-avatar"><Icon name="sparkles" size={26} style={{ color: "#fff" }} /></div>
            <div style={{ flex: 1 }}>
              <div className="font-display" style={{ fontSize: "clamp(16px,2vw,22px)", fontWeight: 700 }}>{t({ vi: "Trợ lý ảo", en: "Virtual Assistant" })}</div>
              <div style={{ fontSize: "clamp(12px,1.4vw,16px)", color: "var(--ok)", fontWeight: 600, display: "flex", alignItems: "center", gap: 6 }}><span className="k-live-dot" />{t({ vi: "Đang hỗ trợ bạn", en: "Here to help you" })}</div>
            </div>
            {/* step status in header */}
            <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "7px 13px", background: engineRunning ? "var(--primary-soft)" : "var(--ok-soft)", borderRadius: "var(--r-md)", border: "1px solid " + (engineRunning ? "var(--primary-soft-2)" : "#c4e6d1") }}>
              <span className={"k-toast-spin" + (engineRunning ? " spin" : "")}><Icon name={engineRunning ? "refresh" : "checkCircle"} size={15} style={{ color: engineRunning ? "var(--primary)" : "var(--ok)" }} /></span>
              <span style={{ fontSize: 13, fontWeight: 600, color: engineRunning ? "var(--primary-deep)" : "var(--ok)", maxWidth: 240 }}>{t(step.status)}</span>
            </div>
          </div>

          {/* 2-column body */}
          <div style={{ flex: 1, minHeight: 0, display: "flex", overflow: "hidden", flexDirection: isLandscape ? "column" : "row" }}>
            {/* chat messages */}
            <div className="k-ai-body" ref={chatRef} style={{ flex: "1 1 0", borderRight: isLandscape ? "none" : "1px solid var(--hairline)", borderBottom: isLandscape ? "1px solid var(--hairline)" : "none" }}>
              {msgs.map((m, i) => (
                <div key={i} className={"k-bubble " + m.role}>{m.text}</div>
              ))}
              {typing && <div className="k-bubble ai typing"><span/><span/><span/></div>}
            </div>

            {/* action panel — column in portrait, row strip in landscape */}
            <div style={{ flex: isLandscape ? "0 0 auto" : "0 0 260px", display: "flex", flexDirection: isLandscape ? "row" : "column", gap: 10, padding: isLandscape ? "10px 16px" : "14px 16px", background: "var(--pearl)", flexWrap: "wrap", alignItems: isLandscape ? "center" : "stretch" }}>
              <button className={"press k-cta" + (phase !== "action" ? " busy" : "")} onClick={doPrimary} disabled={phase !== "action"}
                style={{ height: isLandscape ? 58 : 76, fontSize: isLandscape ? 15 : 18, borderRadius: "var(--r-lg)", flexShrink: 0, flex: isLandscape ? "1 1 200px" : undefined }}>
                {phase !== "action" && idx !== STEPS.length - 1 ? <span className="k-cta-spin" /> : <Icon name={ctaIcon()} size={20} style={{ color: "var(--on-cta)" }} />}
                {ctaLabel()}
              </button>
              {step.mode === "card" && phase === "action" && !cardRead && (
                <button className="kb-cccd-btn" style={{ margin: 0, padding: "10px 12px", fontSize: 14, flex: isLandscape ? "0 0 auto" : undefined }}
                  onClick={() => openKb("number", t({ vi: "Nhập số CCCD", en: "Enter ID" }), "", (v) => { if (v.length >= 9) { setCardRead(true); pushAI(t({ vi: "Đã nhập CCCD thủ công.", en: "Manual ID accepted." })); after(900, goNext); } })}>
                  <svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="7" y1="9" x2="7.01" y2="9"/><line x1="12" y1="9" x2="12.01" y2="9"/><line x1="17" y1="9" x2="17.01" y2="9"/><line x1="7" y1="13" x2="7.01" y2="13"/><line x1="17" y1="13" x2="17.01" y2="13"/></svg>
                  {t({ vi: "Nhập thủ công", en: "Enter manually" })}
                </button>
              )}
              {!isLandscape && <div style={{ flex: 1 }} />}
              {!isLandscape && (
                <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
                  {HELP.slice(0, 3).map((h, i) => (
                    <button key={i} className="press k-chip" style={{ fontSize: 13.5, padding: "8px 12px", textAlign: "left" }} onClick={() => askHelp(h)}>{t(h.q)}</button>
                  ))}
                </div>
              )}
              <button className="press k-help-btn" style={{ width: isLandscape ? "auto" : "100%", justifyContent: "center", height: isLandscape ? 58 : 52, fontSize: 14, flex: isLandscape ? "0 0 auto" : undefined }}
                onClick={() => askHelp(HELP[3])}>
                <Icon name="help" size={17} style={{ color: "var(--primary)" }} />
                {t({ vi: "Gọi cán bộ", en: "Call staff" })}
              </button>
            </div>
          </div>

          {/* input row */}
          <div className="k-ai-input">
            <div className="k-ai-field" onClick={() => openKb("text", t({ vi: "Câu hỏi", en: "Question" }), draft, (v) => { setDraft(v); })}>
              {draft ? <span style={{ color: "var(--ink)" }}>{draft}</span> : <span style={{ color: "var(--ink-4)" }}>{t({ vi: "Nhập câu hỏi của bạn…", en: "Type your question…" })}</span>}
              <span style={{ marginLeft: "auto", display: "flex", alignItems: "center", color: "var(--ink-4)" }}>
                <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="7" y1="9" x2="7.01" y2="9"/><line x1="12" y1="9" x2="12.01" y2="9"/><line x1="17" y1="9" x2="17.01" y2="9"/><line x1="7" y1="13" x2="7.01" y2="13"/><line x1="12" y1="13" x2="12.01" y2="13"/><line x1="17" y1="13" x2="17.01" y2="13"/></svg>
              </span>
            </div>
            <button className="press" onClick={() => { if (draft.trim()) sendDraft(); else openKb("text", t({ vi: "Câu hỏi", en: "Question" }), draft, (v) => { setDraft(v); }); }} aria-label="Send"><Icon name="send" size={20} style={{ color: "var(--on-cta)" }} /></button>
          </div>
        </section>
      </main>

      <VirtualKeyboard
        visible={kb.open}
        mode={kb.mode}
        label={kb.label}
        value={kb.value}
        onChange={(v) => setKb((k) => ({ ...k, value: typeof v === "function" ? v(k.value) : v }))}
        onConfirm={(v) => { if (kb.onConfirm) kb.onConfirm(v); closeKb(); }}
        onClose={closeKb}
        lang={lang}
      />
    </div>
  );
}

/* ============================================================
   KioskRoot — 4-state machine: idle → home → voice | active
   ============================================================ */
const IDLE_TIMEOUT = 60;

function KioskRoot() {
  const [screen, setScreen] = useState("idle"); // idle | home | voice | active
  const [lang, setLang] = useState("vi");
  const [orientation, setOrientation] = useState(
    () => localStorage.getItem('kiosk-orientation') || 'auto'
  );
  const inactivity = useRef(null);

  useEffect(() => {
    const h = (e) => setOrientation(e.detail);
    window.addEventListener("kiosk-orientation", h);
    return () => window.removeEventListener("kiosk-orientation", h);
  }, []);

  const resetTimer = useCallback(() => {
    clearTimeout(inactivity.current);
    inactivity.current = setTimeout(() => setScreen("idle"), IDLE_TIMEOUT * 1000);
  }, []);

  // idle tap → home dashboard
  const wake = useCallback(() => { setScreen("home"); resetTimer(); }, [resetTimer]);

  // home selects a service
  const handleHomeSelect = useCallback((id) => {
    setScreen(id === "ai_assistant" ? "voice" : "active");
    resetTimer();
  }, [resetTimer]);

  // voice selects a service → active
  const selectService = useCallback(() => { setScreen("active"); resetTimer(); }, [resetTimer]);

  // back navigation
  const backToIdle = useCallback(() => { setScreen("idle"); clearTimeout(inactivity.current); }, []);
  const backToHome = useCallback(() => { setScreen("home"); resetTimer(); }, [resetTimer]);

  useEffect(() => {
    if (screen === "idle") return;
    const h = () => resetTimer();
    window.addEventListener("pointerdown", h);
    window.addEventListener("keydown", h);
    resetTimer();
    return () => {
      window.removeEventListener("pointerdown", h);
      window.removeEventListener("keydown", h);
      clearTimeout(inactivity.current);
    };
  }, [screen, resetTimer]);

  const ov = { position:"absolute", inset:0, zIndex:20 };
  return (
    <div style={{ position:"relative", width:"100%", height:"100%" }}>
      {/* Active workflow — always mounted, hidden behind overlays */}
      <div style={{ visibility: screen==="active" ? "visible" : "hidden", height:"100%" }}>
        <App externalLang={lang} onLangChange={setLang} orientation={orientation} />
      </div>
      {screen==="voice" && <div style={ov}><VoiceScreen onSelect={selectService} onBack={backToHome} lang={lang} /></div>}
      {screen==="home"  && <div style={ov}><HomeScreen onSelect={handleHomeSelect} onBack={backToIdle} lang={lang} onLangChange={setLang} /></div>}
      {screen==="idle"  && <div style={ov}><IdleScreen onWake={wake} lang={lang} /></div>}
    </div>
  );
}

ReactDOM.createRoot(document.getElementById("root")).render(<KioskRoot />);

