/* ============================================================
   Kiosk — shared data: i18n strings + the 8-step workflow
   ============================================================ */
const KIOSK = (function () {
  // tiny i18n helper: t({vi,en}) resolves against current KIOSK.lang
  const I = {};

  // ---- The generic 8-step public-service automation workflow ----
  // scene = which mock dichvucong screen to render
  // mode  = 'auto' (engine acts) | 'card' | 'scan' | 'confirm' (needs citizen)
  // hot   = highlight target {x,y,w,h} in % of the browser viewport
  const STEPS = [
    {
      id: "open", scene: "home", mode: "auto",
      title: { vi: "Mở Cổng Dịch vụ công", en: "Open the public service portal" },
      status: { vi: "Đang mở dichvucong.gov.vn", en: "Opening dichvucong.gov.vn" },
      hot: { x: 50, y: 30, w: 60, h: 16 },
      ai: { vi: "Tôi đang mở Cổng Dịch vụ công Quốc gia cho bạn. Bạn chỉ cần làm theo hướng dẫn nhé.", en: "I'm opening the National Public Service Portal for you. Just follow along." },
    },
    {
      id: "select", scene: "services", mode: "auto",
      title: { vi: "Chọn thủ tục", en: "Select the procedure" },
      status: { vi: "Đang chọn “Đăng ký khai sinh”", en: "Selecting “Birth registration”" },
      hot: { x: 26, y: 47, w: 44, h: 18 },
      ai: { vi: "Tôi sẽ chọn giúp bạn thủ tục bạn cần. Nếu sai, hãy chạm “Cần trợ giúp”.", en: "I'll pick the procedure you need. If it's wrong, tap “Need help”." },
    },
    {
      id: "auth", scene: "login", mode: "card",
      title: { vi: "Xác thực CCCD", en: "Verify Citizen ID" },
      status: { vi: "Vui lòng đặt thẻ CCCD lên đầu đọc", en: "Please place your ID card on the reader" },
      hot: { x: 50, y: 52, w: 70, h: 26 },
      ai: { vi: "Hãy đặt thẻ Căn cước công dân gắn chip lên khay đầu đọc bên dưới màn hình. Thông tin của bạn không được lưu lại.", en: "Place your chip-based Citizen ID card on the reader tray below the screen. Your data is never stored." },
    },
    {
      id: "fill", scene: "form", mode: "auto",
      title: { vi: "Điền thông tin", en: "Fill in details" },
      status: { vi: "Đang điền thông tin từ thẻ CCCD", en: "Auto-filling details from your ID card" },
      hot: { x: 50, y: 44, w: 78, h: 40 },
      ai: { vi: "Thông tin được điền tự động từ thẻ của bạn — bạn không phải gõ gì cả. Hãy kiểm tra lại cho đúng.", en: "Details are filled automatically from your card — no typing needed. Please double-check them." },
    },
    {
