/* ── Icon library ────────────────────────────────────────── */
function HIcon({ name, size = 32, color = "#005CBF" }) {
  const p = { viewBox:"0 0 24 24", width:size, height:size, fill:"none",
    stroke:color, strokeWidth:1.8, strokeLinecap:"round", strokeLinejoin:"round" };
  if (name==="file")   return <svg {...p}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>;
  if (name==="folder") return <svg {...p}><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>;
  if (name==="ticket") return <svg {...p}><path d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 0 0-2 2v3a2 2 0 0 1 0 4v3a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-3a2 2 0 0 1 0-4V7a2 2 0 0 0-2-2H5z"/></svg>;
  if (name==="search") return <svg {...p}><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>;
  if (name==="bot")    return <svg {...p}><rect x="3" y="11" width="18" height="10" rx="2"/><path d="M12 11V7"/><circle cx="12" cy="5" r="2"/><line x1="8" y1="15" x2="8.01" y2="15"/><line x1="16" y1="15" x2="16.01" y2="15"/><path d="M7 11V9a5 5 0 0 1 10 0v2"/></svg>;
  if (name==="star")   return <svg {...p}><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" fill={color} opacity=".2"/><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>;
  if (name==="home")   return <svg {...p}><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>;
  if (name==="help")   return <svg {...p}><circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>;
  if (name==="back")   return <svg {...p}><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>;
  if (name==="exit")   return <svg {...p}><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>;
  if (name==="check")  return <svg {...p}><polyline points="20 6 9 17 4 12"/></svg>;
  if (name==="user")   return <svg {...p}><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>;
  if (name==="globe")  return <svg {...p}><circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2c2.5 3 4 6.5 4 10s-1.5 7-4 10M12 2c-2.5 3-4 6.5-4 10s1.5 7 4 10"/></svg>;
  return null;
}

/* ── Live clock ──────────────────────────────────────────── */
function HomeClock({ lang }) {
  const [now, setNow] = hUseState(new Date());
  hUseEffect(() => { const id = setInterval(() => setNow(new Date()), 1000); return () => clearInterval(id); }, []);
  const DAYS = {
    vi: ["CN","T.Hai","T.Ba","T.Tư","T.Năm","T.Sáu","T.Bảy"],
    en: ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"],
  };
  const hh = String(now.getHours()).padStart(2,"0");
  const mm = String(now.getMinutes()).padStart(2,"0");
  const ss = String(now.getSeconds()).padStart(2,"0");
  const day = DAYS[lang][now.getDay()];
  const date = lang==="vi"
    ? `${day}, ${now.getDate()}/${now.getMonth()+1}/${now.getFullYear()}`
    : `${day}, ${now.toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"})}`;
  return (
    <div style={{textAlign:"right", lineHeight:1.15}}>
      <div style={{fontSize:"clamp(28px,2.8vw,44px)", fontWeight:700, fontFamily:"var(--font-display)", letterSpacing:"-.03em", fontVariantNumeric:"tabular-nums", color:"#1F2937"}}>
        {hh}<span style={{opacity:.45, animation:"colonblink .7s step-end infinite"}}>:</span>{mm}
        <span style={{fontSize:".5em", opacity:.4, marginLeft:3, fontVariantNumeric:"tabular-nums"}}>{ss}</span>
      </div>
      <div style={{fontSize:"clamp(12px,1.3vw,16px)", color:"#6B7280", fontWeight:500, marginTop:1}}>{date}</div>
    </div>
  );
}

/* ── Header ──────────────────────────────────────────────── */
