}

/* ── Service Card ─────────────────────────────────────────── */
function HomeCard({ card, t, onSelect }) {
  const [hover, setHover] = hUseState(false);
  const [press, setPress] = hUseState(false);
  const active = hover || press;
  return (
    <button
      onPointerEnter={() => setHover(true)}
      onPointerLeave={() => { setHover(false); setPress(false); }}
      onPointerDown={() => setPress(true)}
      onPointerUp={() => { setPress(false); onSelect(card.id); }}
      style={{
        display:"flex", flexDirection:"column", alignItems:"flex-start",
        gap:"clamp(12px,1.6vh,20px)",
        padding:"clamp(22px,2.8vh,38px) clamp(22px,2.4vw,34px)",
        background: active ? card.bg : "#fff",
        border:`2px solid ${active ? card.color : "#E5E7EB"}`,
        borderRadius:"clamp(16px,1.8vw,24px)",
        cursor:"pointer", textAlign:"left",
        transition:"all .16s ease",
        transform: press ? "scale(0.97)" : active ? "translateY(-4px)" : "none",
        boxShadow: active ? `0 12px 36px ${card.color}28, 0 2px 8px rgba(0,0,0,.06)` : "0 2px 8px rgba(0,0,0,.05)",
        minHeight:"clamp(150px,17.5vh,240px)",
        position:"relative", overflow:"hidden",
