        borderRadius:"24px 0 0 24px",
        transition:"opacity .16s",
      }}/>

      {/* badge */}
      {card.badge && (
        <div style={{
          position:"absolute", top:"clamp(12px,1.4vh,18px)", right:"clamp(12px,1.4vw,18px)",
