        position:"absolute", bottom:"clamp(16px,1.8vh,24px)", right:"clamp(18px,2vw,26px)",
        width:"clamp(32px,3.8vh,46px)", height:"clamp(32px,3.8vh,46px)",
        borderRadius:"50%",
        background: active ? card.color : card.bg,
        border:`1.5px solid ${active ? card.color : card.border}`,
        display:"grid", placeItems:"center",
        transition:"all .16s",
