}

/* ---- Live clock ---- */
function LiveClock({ lang }) {
  const [now, setNow] = iUseState(new Date());
  iUseEffect(() => { const id = setInterval(() => setNow(new Date()), 1000); return () => clearInterval(id); }, []);
  const days = {
    vi: ["Chủ nhật", "Thứ hai", "Thứ ba", "Thứ tư", "Thứ năm", "Thứ sáu", "Thứ bảy"],
    en: ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"],
  };
  const hh = String(now.getHours()).padStart(2, "0");
  const mm = String(now.getMinutes()).padStart(2, "0");
  const ss = String(now.getSeconds()).padStart(2, "0");
  const day = days[lang][now.getDay()];
  const date = lang === "vi"
    ? `${day}, ${now.getDate()}/${now.getMonth() + 1}/${now.getFullYear()}`
    : `${day}, ${now.toLocaleDateString("en-GB", { day: "numeric", month: "long", year: "numeric" })}`;
  return (
    <div style={{ textAlign: "center" }}>
      <div style={{ fontFamily: "var(--font-display)", fontWeight: 700, fontSize: 108, lineHeight: 1, letterSpacing: "-.04em", fontVariantNumeric: "tabular-nums", color: "#ffffff", textShadow: "0 4px 40px rgba(0,0,0,.5)" }}>
        {hh}<span style={{ opacity: .55, animation: "colonblink 1s step-end infinite" }}>:</span>{mm}
        <span style={{ fontSize: 56, fontWeight: 400, opacity: .5, marginLeft: 4 }}>{ss}</span>
      </div>
      <div style={{ fontSize: 26, color: "rgba(255,255,255,.65)", fontWeight: 400, marginTop: -4, letterSpacing: ".01em" }}>{date}</div>
    </div>
  );
}

/* ---- Main IdleScreen ---- */
function IdleScreen({ onWake, lang }) {
  const SLIDES = window.KIOSK.IDLE_SLIDES;
  const [idx, setIdx] = iUseState(0);
  const [prev, setPrev] = iUseState(null);
  const [fading, setFading] = iUseState(false);
  const tmr = iUseRef(null);
  const t = (o) => (o ? o[lang] : "");

  const advance = () => {
    setFading(true);
    setTimeout(() => {
      setPrev(idx);
      setIdx((i) => (i + 1) % SLIDES.length);
      setFading(false);
    }, 700);
  };

  const goSlide = (n) => {
    if (n === idx) return;
    setFading(true);
    setTimeout(() => { setIdx(n); setFading(false); }, 700);
  };

  iUseEffect(() => {
    const cur = SLIDES[idx];
    tmr.current = setTimeout(advance, (cur.duration || 6) * 1000);
    return () => clearTimeout(tmr.current);
  }, [idx]);

  const slide = SLIDES[idx];

  return (
    <div
      className="idle-root"
      onClick={onWake}
      style={{ position: "absolute", inset: 0, zIndex: 50, cursor: "pointer", userSelect: "none" }}
    >
      {/* ---- background slides ---- */}
      <div className="idle-bg" style={{ background: slide.bg, transition: "background 1s ease" }} />
      <Decor kind={slide.decor} color={slide.accentColor} />

      {/* top bar: status + lang indicator */}
      <div style={{ position: "absolute", top: 0, left: 0, right: 0, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "36px 44px 0", zIndex: 6 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
