/* ============================================================
   Kiosk — Virtual Keyboard  (floating + draggable)
   v2: Floating panel, draggable by header, physical keyboard
   passthrough, "Tôi có thể giúp gì cho bạn?" AI header.
   ============================================================ */
const {
  useState: kUseState, useEffect: kUseEffect,
  useCallback: kUseCallback, useRef: kUseRef,
} = React;

/* ---- Vietnamese tone data ---- */
const VI_TONES  = ["à","á","ả","ã","ạ","ă","â","ê","ô","ơ","ư","đ"];
const VI_TONES_UPPER = ["À","Á","Ả","Ã","Ạ","Ă","Â","Ê","Ô","Ơ","Ư","Đ"];

const ROWS = [
  ["1","2","3","4","5","6","7","8","9","0"],
  ["q","w","e","r","t","y","u","i","o","p"],
  ["a","s","d","f","g","h","j","k","l"],
  ["z","x","c","v","b","n","m"],
];
const NUMPAD = [["1","2","3"],["4","5","6"],["7","8","9"],[".","0","⌫"]];

/* ---- Individual key ---- */
function KKey({ label, display, flex = 1, h = 72, onPress, variant = "default" }) {
  const [dn, setDn] = kUseState(false);
  const fire = () => { setDn(true); onPress(label); setTimeout(() => setDn(false), 90); };
  const bg = {
    default: dn ? "rgba(255,255,255,.28)" : "rgba(255,255,255,.11)",
    dim:     dn ? "rgba(255,255,255,.18)" : "rgba(255,255,255,.06)",
    accent:  dn ? "var(--primary-strong)" : "var(--primary)",
    tone:    dn ? "rgba(206,122,88,.55)"  : "rgba(206,122,88,.18)",
  }[variant] || "rgba(255,255,255,.11)";
  return (
    <button onPointerDown={(e) => { e.stopPropagation(); fire(); }}
      style={{
        flex, height: h, borderRadius: 12,
        border: "1px solid rgba(255,255,255,.1)",
        background: bg,
        color: variant === "accent" ? "#fff" : variant === "dim" ? "rgba(255,255,255,.45)" : "#fff",
        fontFamily: "var(--font-body)", fontWeight: variant === "accent" ? 700 : 600,
        fontSize: typeof display === "string" && display.length > 2 ? 15 : 24,
        display: "flex", alignItems: "center", justifyContent: "center",
        cursor: "pointer", padding: 0, minWidth: 0, userSelect: "none",
        transform: dn ? "scale(0.9)" : "scale(1)",
        transition: "background .08s, transform .08s",
        boxShadow: dn ? "none" : "0 2px 4px rgba(0,0,0,.3)",
      }}>
      {display ?? label}
    </button>
  );
}

const BkSp = () => (
  <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M21 4H8l-7 8 7 8h13a2 2 0 0 0 2-2V6a2 2 0 0 0-2-2z"/>
    <line x1="18" y1="9" x2="12" y2="15"/><line x1="12" y1="9" x2="18" y2="15"/>
  </svg>
);
const CapsIcon = ({ on }) => (
  <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke={on ? "var(--primary)" : "currentColor"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="17 11 12 6 7 11"/><line x1="12" y1="6" x2="12" y2="18"/>
  </svg>
);

/* ---- QWERTY board ---- */
function QBoard({ value, onChange, onConfirm, onClose, label, lang, t }) {
  const [caps, setCaps] = kUseState(false);
  const tap = (k) => {
    if (k === "⌫") { onChange((v) => v.slice(0, -1)); return; }
    if (k === "CAPS") { setCaps((c) => !c); return; }
    if (k === "SPC") { onChange((v) => v + " "); return; }
    if (VI_TONES.includes(k)) { onChange((v) => v + (caps ? VI_TONES_UPPER[VI_TONES.indexOf(k)] : k)); return; }
    onChange((v) => v + (caps ? k.toUpperCase() : k));
  };
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:7 }}>
      {/* row 0: numbers */}
      <div style={{ display:"flex", gap:7 }}>
        {ROWS[0].map((k) => <KKey key={k} label={k} onPress={tap} h={62} />)}
        <KKey label="⌫" display={<BkSp/>} flex={1.4} h={62} variant="dim" onPress={tap} />
      </div>
      {/* row 1: qwerty */}
      <div style={{ display:"flex", gap:7 }}>
        {ROWS[1].map((k) => <KKey key={k} label={k} display={caps?k.toUpperCase():k} onPress={tap} h={66} />)}
      </div>
      {/* row 2: asdf */}
      <div style={{ display:"flex", gap:7, paddingLeft:"4%" }}>
        {ROWS[2].map((k) => <KKey key={k} label={k} display={caps?k.toUpperCase():k} onPress={tap} h={66} />)}
      </div>
      {/* row 3: zxcv + caps */}
      <div style={{ display:"flex", gap:7 }}>
        <KKey label="CAPS" display={<CapsIcon on={caps}/>} flex={1.55} variant={caps?"accent":"dim"} onPress={tap} h={66} />
        {ROWS[3].map((k) => <KKey key={k} label={k} display={caps?k.toUpperCase():k} onPress={tap} h={66} />)}
        <KKey label="⌫" display={<BkSp/>} flex={1.55} variant="dim" onPress={tap} h={66} />
      </div>
      {/* Vietnamese tone strip */}
      {lang === "vi" && (
        <div style={{ display:"flex", gap:6, background:"rgba(206,122,88,.1)", border:"1px solid rgba(206,122,88,.22)", borderRadius:12, padding:"7px 8px", alignItems:"center", flexWrap:"wrap" }}>
          <span style={{ fontSize:11.5, color:"rgba(206,122,88,.9)", fontWeight:700, letterSpacing:".05em", textTransform:"uppercase", padding:"0 4px", flex:"0 0 auto" }}>VI</span>
          {VI_TONES.map((k, i) => (
            <KKey key={k} label={k} display={caps?VI_TONES_UPPER[i]:k} flex="0 0 auto" onPress={tap} h={52} variant="tone" />
          ))}
        </div>
      )}
      {/* bottom row */}
      <div style={{ display:"flex", gap:7 }}>
        <KKey label="SPC" display={t({vi:"Khoảng trắng", en:"Space"})} flex={6} variant="dim" onPress={tap} h={62} />
        <button onPointerDown={(e) => { e.stopPropagation(); onClose(); }}
          style={{ flex:1.4, height:62, border:"1px solid rgba(255,255,255,.14)", background:"rgba(255,255,255,.06)", borderRadius:12, color:"rgba(255,255,255,.6)", fontSize:15, fontWeight:600, cursor:"pointer", fontFamily:"var(--font-body)" }}>
          {t({vi:"Huỷ",en:"Cancel"})}
        </button>
        <button onPointerDown={(e) => { e.stopPropagation(); onConfirm(value); }}
          style={{ flex:2.2, height:62, border:"none", background:"var(--cta)", borderRadius:12, color:"var(--on-cta)", fontSize:17, fontWeight:700, cursor:"pointer", fontFamily:"var(--font-display)", boxShadow:"0 4px 14px var(--cta-ring)" }}>
          {t({vi:"Xong ✓",en:"Done ✓"})}
        </button>
      </div>
    </div>
  );
}

/* ---- Numpad board ---- */
function NumBoard({ value, onChange, onConfirm, onClose, label, t }) {
  const tap = (k) => {
    if (k === "⌫") onChange((v) => v.slice(0,-1));
    else onChange((v) => v + k);
  };
  return (
    <div style={{ display:"flex", gap:16 }}>
      <div style={{ flex:1, display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:9 }}>
        {NUMPAD.flat().map((k,i) => <KKey key={i} label={k} h={84} variant={k==="⌫"?"dim":"default"} onPress={tap} />)}
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:9, flex:"0 0 148px" }}>
        <div style={{ flex:1, background:"rgba(255,255,255,.06)", border:"1px solid rgba(255,255,255,.1)", borderRadius:12, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:4 }}>
          <div style={{ fontFamily:"var(--font-display)", fontSize:36, fontWeight:700, color:"#fff", letterSpacing:".04em", fontVariantNumeric:"tabular-nums" }}>{value || <span style={{ color:"rgba(255,255,255,.2)" }}>—</span>}</div>
          <div style={{ fontSize:13, color:"rgba(255,255,255,.35)" }}>{label}</div>
        </div>
        <button onPointerDown={(e) => {e.stopPropagation(); onChange(""); }}
          style={{ height:56, border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.05)", borderRadius:12, color:"rgba(255,255,255,.5)", fontSize:15, fontWeight:600, cursor:"pointer", fontFamily:"var(--font-body)" }}>
          {t({vi:"Xóa hết",en:"Clear"})}
        </button>
        <button onPointerDown={(e) => {e.stopPropagation(); onConfirm(value); }}
          style={{ height:70, border:"none", background:"var(--cta)", borderRadius:12, color:"var(--on-cta)", fontSize:18, fontWeight:700, cursor:"pointer", fontFamily:"var(--font-display)", boxShadow:"0 4px 14px var(--cta-ring)" }}>
          {t({vi:"Xác nhận",en:"Confirm"})}
        </button>
        <button onPointerDown={(e) => {e.stopPropagation(); onClose(); }}
          style={{ height:54, border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.05)", borderRadius:12, color:"rgba(255,255,255,.5)", fontSize:15, fontWeight:600, cursor:"pointer", fontFamily:"var(--font-body)" }}>
          {t({vi:"Huỷ",en:"Cancel"})}
        </button>
      </div>
    </div>
  );
}

/* ============================================================
   VirtualKeyboard — floating draggable panel
   ============================================================ */
function VirtualKeyboard({ visible, mode="text", label, value, onChange, onConfirm, onClose, lang }) {
  const t = (o) => o ? o[lang] : "";
  const [show, setShow] = kUseState(false); // controls fade-in
  const [pos, setPos] = kUseState(() => ({
    x: Math.max(20, (window.innerWidth - 1000) / 2),
    y: Math.max(100, window.innerHeight * 0.5),
  }));
  const drag = kUseRef({ on: false, sx: 0, sy: 0, px: 0, py: 0 });
  const panelRef = kUseRef(null);

  /* fade in with RAF so CSS transition fires */
  kUseEffect(() => {
    if (visible) { const id = requestAnimationFrame(() => setShow(true)); return () => cancelAnimationFrame(id); }
    setShow(false);
  }, [visible]);

  /* physical keyboard passthrough */
  kUseEffect(() => {
    if (!visible) return;
    const h = (e) => {
      if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
      if (e.key === "Backspace") { e.preventDefault(); onChange((v) => v.slice(0,-1)); return; }
      if (e.key === "Enter")     { onConfirm(value); return; }
      if (e.key === "Escape")    { onClose(); return; }
      if (e.key === " ")         { e.preventDefault(); onChange((v) => v+" "); return; }
      if (e.key.length === 1)    { onChange((v) => v + e.key); }
    };
    window.addEventListener("keydown", h);
    return () => window.removeEventListener("keydown", h);
  }, [visible, value, onChange, onConfirm, onClose]);

  /* drag: full-screen — no scale transform needed */
  const getScale = () => 1;

  const onDragDown = kUseCallback((e) => {
    drag.current = { on: true, sx: e.clientX, sy: e.clientY, px: pos.x, py: pos.y };
    e.currentTarget.setPointerCapture(e.pointerId);
    e.stopPropagation();
  }, [pos]);

  const onDragMove = kUseCallback((e) => {
    if (!drag.current.on) return;
    const sc = getScale();
    const dx = (e.clientX - drag.current.sx) / sc;
    const dy = (e.clientY - drag.current.sy) / sc;
    setPos({
      x: Math.max(0, Math.min(window.innerWidth - 1000, drag.current.px + dx)),
      y: Math.max(0, Math.min(window.innerHeight - 500, drag.current.py + dy)),
    });
    e.stopPropagation();
  }, []);

  const onDragUp = kUseCallback(() => { drag.current.on = false; }, []);

  if (!visible) return null;

  return (
    <div ref={panelRef}
      style={{
        position: "absolute",
        left: pos.x, top: pos.y,
        width: 1000, zIndex: 40,
        background: "rgba(12,9,6,.96)",
        backdropFilter: "blur(28px)",
        border: "1px solid rgba(255,255,255,.12)",
        borderRadius: 28,
        boxShadow: "0 28px 80px rgba(0,0,0,.6), 0 0 0 1px rgba(255,255,255,.06)",
        padding: "0 0 20px",
        opacity: show ? 1 : 0,
        transform: show ? "scale(1) translateY(0)" : "scale(0.96) translateY(24px)",
        transition: "opacity .22s ease, transform .22s ease",
      }}
      onPointerMove={onDragMove}
      onPointerUp={onDragUp}
    >
      {/* ---- drag header ---- */}
      <div
        onPointerDown={onDragDown}
        style={{
          display:"flex", alignItems:"center", gap:14,
          padding:"14px 20px 12px", cursor:"grab",
          borderBottom:"1px solid rgba(255,255,255,.08)",
          borderRadius:"28px 28px 0 0",
          userSelect:"none",
        }}
      >
        {/* drag grip */}
        <div style={{ display:"flex", flexDirection:"column", gap:3, flex:"0 0 auto", opacity:.4 }}>
          {[0,1,2].map((i) => <div key={i} style={{ width:20, height:2, borderRadius:99, background:"#fff" }} />)}
        </div>
        <div style={{ flex:1 }}>
          <div style={{ fontFamily:"var(--font-display)", fontSize:20, fontWeight:700, color:"#fff", letterSpacing:"-.01em" }}>
            {t({vi:"Tôi có thể giúp gì cho bạn?", en:"How can I help you?"})}
          </div>
          {label && <div style={{ fontSize:14, color:"rgba(255,255,255,.4)", marginTop:2 }}>{label}</div>}
        </div>
        {/* mode toggle */}
        <button onPointerDown={(e) => e.stopPropagation()} onClick={() => {}}
          style={{ padding:"7px 14px", borderRadius:99, border:"1px solid rgba(255,255,255,.15)", background:"rgba(255,255,255,.07)", color:"rgba(255,255,255,.6)", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:"var(--font-body)" }}>
          {mode === "number" ? "ABC" : "123"}
        </button>
        {/* close */}
        <button onPointerDown={(e) => e.stopPropagation()} onClick={onClose}
          style={{ width:40, height:40, borderRadius:"50%", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.06)", color:"rgba(255,255,255,.55)", display:"grid", placeItems:"center", cursor:"pointer", flex:"0 0 auto" }}>
          <svg viewBox="0 0 24 24" width="17" height="17" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round"><line x1="6" y1="6" x2="18" y2="18"/><line x1="18" y1="6" x2="6" y2="18"/></svg>
        </button>
      </div>

      {/* ---- input preview bar ---- */}
      <div style={{ margin:"12px 20px 10px", background:"rgba(255,255,255,.07)", border:"1px solid rgba(255,255,255,.12)", borderRadius:14, padding:"11px 18px", display:"flex", alignItems:"center", gap:10, minHeight:54 }}>
        <div style={{ flex:1, fontFamily:"var(--font-display)", fontSize:26, fontWeight:600, color:"#fff", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
          {value
            ? <span>{value}<span style={{ borderRight:"2px solid var(--primary)", marginLeft:1, animation:"colonblink .7s step-end infinite" }}>&nbsp;</span></span>
            : <span style={{ color:"rgba(255,255,255,.18)", fontWeight:400, fontSize:20 }}>{t({vi:"Nhập văn bản…", en:"Type here…"})}</span>
          }
        </div>
        {value && (
          <button onClick={() => onChange("")}
            style={{ flex:"0 0 auto", background:"rgba(255,255,255,.08)", border:"none", color:"rgba(255,255,255,.4)", padding:"6px 12px", borderRadius:8, fontSize:14, cursor:"pointer" }}>✕</button>
        )}
      </div>

      {/* ---- keys ---- */}
      <div style={{ padding:"0 18px" }}>
        {mode === "number"
          ? <NumBoard value={value} onChange={onChange} onConfirm={onConfirm} onClose={onClose} label={label} t={t} />
          : <QBoard value={value} onChange={onChange} onConfirm={onConfirm} onClose={onClose} label={label} lang={lang} t={t} />
