      <div style={{ display:"flex", justifyContent:"center", marginTop:8 }}>
        <div style={{ display:"flex", alignItems:"center", gap:8, padding:"5px 14px", borderRadius:99, border:"1px solid rgba(255,255,255,.08)", background:"rgba(255,255,255,.04)" }}>
          <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="rgba(255,255,255,.35)" strokeWidth="1.7" strokeLinecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="7" y1="9" x2="7.01" y2="9"/><line x1="12" y1="9" x2="12.01" y2="9"/><line x1="17" y1="9" x2="17.01" y2="9"/><line x1="7" y1="13" x2="7.01" y2="13"/><line x1="17" y1="13" x2="17.01" y2="13"/><line x1="10" y1="13" x2="14" y2="13"/></svg>
          <span style={{ fontSize:13, color:"rgba(255,255,255,.3)" }}>{t({vi:"Hỗ trợ bàn phím vật lý · Enter để xác nhận · Esc để đóng", en:"Physical keyboard supported · Enter to confirm · Esc to close"})}</span>
        </div>
      </div>
    </div>
  );
}

window.VirtualKeyboard = VirtualKeyboard;

