/* ============================================================
   Kiosk — mocked dichvucong.gov.vn screens (8 scenes)
   Rendered inside the Browser Automation View. Government look
   (deep-red portal header) kept distinct from the terracotta
   kiosk chrome on purpose.
   ============================================================ */
const GOV = "#A8232A"; // national portal red
const LINK = "#0a58ca";

function PortalChrome({ t, children }) {
  return (
    <div style={{ position: "absolute", inset: 0, background: "#fff", display: "flex", flexDirection: "column", overflow: "hidden", fontFamily: "var(--font-body)" }}>
      {/* top utility bar */}
      <div style={{ background: GOV, color: "#fff", padding: "8px 22px", display: "flex", alignItems: "center", gap: 14, fontSize: 14 }}>
        <div style={{ width: 30, height: 30, borderRadius: "50%", background: "#FFD45211", border: "1.5px solid #ffd452", display: "grid", placeItems: "center", color: "#ffd452", fontWeight: 700, fontSize: 15, flex: "0 0 auto" }}>★</div>
        <div style={{ fontWeight: 700, letterSpacing: ".01em", lineHeight: 1.1 }}>
          {t({ vi: "CỔNG DỊCH VỤ CÔNG QUỐC GIA", en: "NATIONAL PUBLIC SERVICE PORTAL" })}
        </div>
        <div style={{ marginLeft: "auto", display: "flex", gap: 18, opacity: .92, fontSize: 13 }}>
          <span>{t({ vi: "Trang chủ", en: "Home" })}</span><span>{t({ vi: "Thủ tục", en: "Procedures" })}</span><span>{t({ vi: "Hỗ trợ", en: "Support" })}</span>
        </div>
      </div>
      <div style={{ flex: 1, position: "relative", overflow: "hidden" }}>{children}</div>
    </div>
  );
}

function Field({ label, value, auto }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
      <span style={{ fontSize: 14, color: "#555", fontWeight: 500 }}>{label}</span>
      <div style={{ position: "relative", padding: "13px 14px", border: "1.5px solid " + (auto ? "#bcd6c4" : "#dadada"), background: auto ? "#f1f9f3" : "#fff", borderRadius: 10, fontSize: 17, fontWeight: 600, color: "#1d1d1f" }}>
        {value}
        {auto && <span style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", fontSize: 11.5, fontWeight: 700, color: "#2E9E6B", background: "#dff0e5", padding: "3px 8px", borderRadius: 999 }}>✓ auto</span>}
      </div>
    </div>
  );
}

function Scene({ scene, t, cardRead, scanned }) {
  const wrap = { position: "absolute", inset: 0, overflow: "auto", padding: "28px 34px" };

  if (scene === "home") return (
    <PortalChrome t={t}>
