          <p style={{ margin: "0 0 20px", fontSize: 17, color: "#555" }}>{t({ vi: "Một cửa — mọi thủ tục hành chính của bạn.", en: "One gateway for all your administrative procedures." })}</p>
          <div style={{ display: "flex", gap: 10, background: "#fff", border: "1.5px solid #e3c9c8", borderRadius: 12, padding: "6px 6px 6px 16px", alignItems: "center" }}>
