  }

  if (scene === "login") return (
    <PortalChrome t={t}>
      <div style={{ ...wrap, display: "grid", placeItems: "center" }}>
        <div style={{ width: "100%", maxWidth: 520, border: "1px solid #ececec", borderRadius: 16, padding: "30px 34px", boxShadow: "0 10px 30px rgba(0,0,0,.06)" }}>
          <div style={{ display: "flex", justifyContent: "center", marginBottom: 14 }}>
            <span style={{ width: 60, height: 60, borderRadius: "50%", background: cardRead ? "#dff0e5" : "#fbeceb", color: cardRead ? "#2E9E6B" : GOV, display: "grid", placeItems: "center", transition: "all .3s" }}><Icon name={cardRead ? "checkCircle" : "idcard"} size={32} /></span>
          </div>
          <h2 style={{ margin: "0 0 4px", textAlign: "center", fontSize: 23, fontWeight: 700, color: "#1d1d1f" }}>{t({ vi: "Đăng nhập bằng CCCD gắn chip", en: "Sign in with chip-based ID" })}</h2>
          <p style={{ margin: "0 0 22px", textAlign: "center", fontSize: 15, color: "#777" }}>{cardRead ? t({ vi: "Đã đọc thẻ thành công", en: "Card read successfully" }) : t({ vi: "Đặt thẻ lên đầu đọc bên dưới", en: "Place your card on the reader below" })}</p>
          <div style={{ border: "2px dashed " + (cardRead ? "#9ccfae" : "#e3c9c8"), borderRadius: 14, padding: "26px 20px", textAlign: "center", background: cardRead ? "#f1f9f3" : "#fdf7f6" }}>
            {cardRead ? (
              <div>
                <div style={{ fontSize: 18, fontWeight: 700, color: "#1d1d1f" }}>NGUYỄN THỊ MAI</div>
                <div style={{ fontSize: 14, color: "#777", marginTop: 4 }}>{t({ vi: "CCCD", en: "ID" })} •••• •••• 4417</div>
              </div>
            ) : (
              <div style={{ fontSize: 15, color: "#a06", opacity: .8 }}>{t({ vi: "Đang chờ thẻ…", en: "Waiting for card…" })}</div>
            )}
          </div>
        </div>
      </div>
    </PortalChrome>
  );

  if (scene === "form") return (
    <PortalChrome t={t}>
      <div style={wrap}>
        <h2 style={{ margin: "0 0 4px", fontSize: 23, fontWeight: 700 }}>{t({ vi: "Thông tin người khai", en: "Applicant details" })}</h2>
        <p style={{ margin: "0 0 20px", fontSize: 14.5, color: "#2E9E6B", fontWeight: 600 }}>{t({ vi: "Đã điền tự động từ thẻ CCCD", en: "Auto-filled from your ID card" })}</p>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
