            <div style={{ fontSize: 13.5, color: "#777", letterSpacing: ".04em", textTransform: "uppercase", fontWeight: 600 }}>{t({ vi: "Mã hồ sơ", en: "Reference code" })}</div>
            <div style={{ fontSize: 30, fontWeight: 700, color: GOV, letterSpacing: ".02em", marginTop: 4 }}>HS-2026-04417</div>
          </div>
        </div>
      </div>
    </PortalChrome>
  );
}
window.Scene = Scene;

