/* ============================================================
   Kiosk — Voice AI Screen
   Citizens speak → AI transcribes + understands intent →
   suggests the right service form → user selects → kiosk workflow
   ============================================================ */
const { useState: vUseState, useEffect: vUseEffect, useRef: vUseRef, useCallback: vUseCallback } = React;

/* ---- Demo conversation scripts (simulate NLP results) ---- */
const DEMOS = [
  {
