        time: { vi: "~10 phút", en: "~10 min" },
        steps: 7 },
    ],
  },
];

/* ---- Waveform bars ---- */
function Waveform({ active, color }) {
  const N = 28;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 4, height: 64, padding: "0 8px" }}>
      {Array.from({ length: N }, (_, i) => {
        const base = Math.abs(Math.sin(i * 0.7)) * 0.6 + 0.2;
        return (
          <div key={i} className={active ? "wv-bar wv-anim" : "wv-bar"} style={{
            width: 6, borderRadius: 3, background: color || "#CE7A58",
            animationDelay: `${(i * 37) % 400}ms`,
            height: active ? undefined : `${Math.round(base * 18 + 6)}px`,
            opacity: active ? undefined : 0.35,
          }} />
        );
      })}
    </div>
  );
}

/* ---- Service suggestion card ---- */
function ServiceCard({ svc, t, onSelect, accent }) {
  const iconMap = { certificate: "file", globe: "globe", idcard: "idcard", house: "building" };
  return (
    <button className={"press v-svc-card" + (svc.primary ? " primary" : "")} onClick={() => onSelect(svc.id)}
      style={svc.primary ? { borderColor: accent, boxShadow: `0 0 0 1px ${accent}44, 0 16px 40px ${accent}22` } : {}}>
      <div style={{ display: "flex", alignItems: "flex-start", gap: 18 }}>
        <div className="v-svc-ico" style={{ background: svc.primary ? accent : "rgba(255,255,255,.1)" }}>
          <svg viewBox="0 0 24 24" width="28" height="28" fill="none" stroke="#fff" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round">
            {iconMap[svc.icon] === "file" && <><path d="M14 3H7a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V8z"/><polyline points="14 3 14 8 19 8"/></>}
            {iconMap[svc.icon] === "globe" && <><circle cx="12" cy="12" r="9"/><path d="M3 12h18M12 3c2.5 2.5 2.5 15 0 18M12 3c-2.5 2.5-2.5 15 0 18"/></>}
            {iconMap[svc.icon] === "idcard" && <><rect x="2.5" y="5" width="19" height="14" rx="2.5"/><circle cx="8" cy="11.5" r="2.2"/><path d="M5 16c.4-1.6 1.6-2.4 3-2.4s2.6.8 3 2.4"/><line x1="14" y1="10" x2="19" y2="10"/><line x1="14" y1="13.5" x2="18" y2="13.5"/></>}
            {iconMap[svc.icon] === "building" && <><rect x="5" y="3" width="14" height="18" rx="1.5"/><path d="M10 21v-4h4v4"/><line x1="9" y1="7" x2="10" y2="7"/><line x1="14" y1="7" x2="15" y2="7"/></>}
          </svg>
        </div>
        <div style={{ flex: 1, textAlign: "left" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
            <span style={{ fontFamily: "var(--font-display)", fontSize: 24, fontWeight: 700, color: "#fff", letterSpacing: "-.01em" }}>{t(svc.name)}</span>
            {svc.primary && <span style={{ fontSize: 13, fontWeight: 700, color: accent, background: accent + "22", padding: "3px 10px", borderRadius: 999 }}>{t({ vi: "Phù hợp nhất", en: "Best match" })}</span>}
          </div>
          <div style={{ fontSize: 17, color: "rgba(255,255,255,.6)", marginTop: 4 }}>{t(svc.desc)}</div>
          <div style={{ display: "flex", gap: 16, marginTop: 10, fontSize: 15, color: "rgba(255,255,255,.5)", alignItems: "center" }}>
            <span>⏱ {t(svc.time)}</span>
            <span>· {svc.steps} {t({ vi: "bước", en: "steps" })}</span>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", width: 52, height: 52, borderRadius: "50%", background: svc.primary ? accent : "rgba(255,255,255,.12)", flex: "0 0 auto", alignSelf: "center" }}>
          <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="4" y1="12" x2="19" y2="12"/><polyline points="13 6 19 12 13 18"/></svg>
        </div>
      </div>
    </button>
  );
}

/* ---- Quick pick all services ---- */
const ALL_SERVICES = [
  { id: "dang_ky_khai_sinh", vi: "Đăng ký khai sinh", en: "Birth registration" },
  { id: "dang_ky_ket_hon", vi: "Đăng ký kết hôn", en: "Marriage" },
  { id: "cap_lai_cccd", vi: "Cấp lại CCCD", en: "Re-issue ID" },
  { id: "dang_ky_thuong_tru", vi: "Đăng ký thường trú", en: "Residence" },
  { id: "bao_hiem", vi: "Bảo hiểm xã hội", en: "Social insurance" },
  { id: "thue", vi: "Khai thuế", en: "Tax filing" },
];

/* ---- Main VoiceScreen ---- */
function VoiceScreen({ onSelect, onBack, lang }) {
  // phase: welcome | listening | processing | result | browse
  const [phase, setPhase] = vUseState("welcome");
  const [demoIdx, setDemoIdx] = vUseState(0);
  const [transcript, setTranscript] = vUseState("");
  const [kbOpen, setKbOpen] = vUseState(false);
  const [kbValue, setKbValue] = vUseState("");
  const KB = window.VirtualKeyboard;
  const tmr = vUseRef([]);
  const t = (o) => (o ? o[lang] : "");
  const demo = DEMOS[demoIdx];

  const after = (ms, fn) => { const id = setTimeout(fn, ms); tmr.current.push(id); return id; };
  vUseEffect(() => () => tmr.current.forEach(clearTimeout), []);

  const startListening = vUseCallback(() => {
    tmr.current.forEach(clearTimeout); tmr.current = [];
    setPhase("listening");
    setTranscript("");
    // simulate speech: type out the query char by char
    const q = t(demo.query);
    let i = 0;
    const typeInterval = setInterval(() => {
      i++;
      setTranscript(q.slice(0, i));
      if (i >= q.length) { clearInterval(typeInterval); after(400, () => setPhase("processing")); }
    }, 55);
    tmr.current.push(typeInterval);
  }, [demo, lang]);

  vUseEffect(() => {
    if (phase === "processing") {
      after(1400, () => setPhase("result"));
    }
  }, [phase]);

  const retry = () => {
    setDemoIdx((i) => (i + 1) % DEMOS.length);
    after(50, startListening);
  };

  const handleKbConfirm = (text) => {
    setKbOpen(false);
    if (!text.trim()) return;
    setTranscript(text);
    setPhase("processing");
    // find best demo match by keyword, fallback to demoIdx
    const lower = text.toLowerCase();
    const match = DEMOS.findIndex((d) => {
      const intent = t(d.intent).toLowerCase();
      const query = t(d.query).toLowerCase();
      return lower.includes(intent.split(" ")[1] || intent) || query.includes(lower.slice(0, 8));
    });
    after(1300, () => { if (match >= 0) setDemoIdx(match); setPhase("result"); });
  };

  const accent = "#CE7A58";

  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 40, background: "linear-gradient(180deg, #140f0a 0%, #1e1510 50%, #160e0a 100%)", display: "flex", flexDirection: "column", overflow: "hidden" }}>

      {/* top nav */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "34px 40px 0", flex: "0 0 auto", position: "relative", zIndex: 5 }}>
        <button onClick={onBack} style={{ display: "flex", alignItems: "center", gap: 10, padding: "11px 18px", background: "rgba(255,255,255,.08)", border: "1px solid rgba(255,255,255,.14)", borderRadius: 999, color: "rgba(255,255,255,.7)", fontSize: 17, fontWeight: 600, cursor: "pointer", fontFamily: "var(--font-body)" }}>
          <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
          {t({ vi: "Quay lại", en: "Back" })}
        </button>
        <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 18px", background: "rgba(206,122,88,.15)", border: "1px solid rgba(206,122,88,.3)", borderRadius: 999 }}>
          <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke={accent} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
          <span style={{ color: accent, fontSize: 15, fontWeight: 700 }}>{t({ vi: "Trợ lý giọng nói", en: "Voice Assistant" })}</span>
        </div>
        <button onClick={() => setPhase("browse")} style={{ display: "flex", alignItems: "center", gap: 10, padding: "11px 18px", background: "rgba(255,255,255,.08)", border: "1px solid rgba(255,255,255,.14)", borderRadius: 999, color: "rgba(255,255,255,.7)", fontSize: 17, fontWeight: 600, cursor: "pointer", fontFamily: "var(--font-body)" }}>
          {t({ vi: "Duyệt thủ tục", en: "Browse" })}
          <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>
        </button>
      </div>

      {/* ---- WELCOME phase ---- */}
      {phase === "welcome" && (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 0, padding: "0 48px", position: "relative" }}>
          {/* ambient glow */}
          <div style={{ position: "absolute", top: "30%", left: "50%", transform: "translate(-50%,-50%)", width: 480, height: 480, borderRadius: "50%", background: `radial-gradient(circle, ${accent}18 0%, transparent 70%)`, pointerEvents: "none" }} />
          <div style={{ fontFamily: "var(--font-display)", fontSize: 46, fontWeight: 700, color: "#fff", textAlign: "center", letterSpacing: "-.02em", marginBottom: 14, lineHeight: 1.1 }}>
            {t({ vi: "Tôi có thể giúp gì\ncho bạn?", en: "How can I help\nyou today?" })}
          </div>
          <div style={{ fontSize: 22, color: "rgba(255,255,255,.5)", textAlign: "center", marginBottom: 56, lineHeight: 1.5 }}>
            {t({ vi: "Nhấn mic và nói tên thủ tục bạn cần", en: "Tap the mic and tell me what you need" })}
          </div>

          {/* BIG MIC BUTTON */}
          <div style={{ position: "relative", marginBottom: 60, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <div className="v-ring v-r1" style={{ borderColor: accent + "30" }} />
            <div className="v-ring v-r2" style={{ borderColor: accent + "1e" }} />
            <div className="v-ring v-r3" style={{ borderColor: accent + "10" }} />
            <button className="press v-mic-btn" onClick={startListening} style={{ background: `linear-gradient(145deg, ${accent}, #b55d3e)`, boxShadow: `0 0 0 0 ${accent}44, 0 24px 60px ${accent}44` }}>
              <svg viewBox="0 0 24 24" width="64" height="64" fill="none" stroke="#fff" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                <line x1="12" y1="19" x2="12" y2="23"/>
                <line x1="8" y1="23" x2="16" y2="23"/>
              </svg>
            </button>
          </div>

          {/* Quick service chips */}
          <div style={{ fontSize: 16, color: "rgba(255,255,255,.35)", marginBottom: 18, letterSpacing: ".04em", textTransform: "uppercase", fontWeight: 600 }}>{t({ vi: "Hoặc chọn trực tiếp", en: "Or select directly" })}</div>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 12, justifyContent: "center" }}>
            {ALL_SERVICES.slice(0, 4).map((s) => (
              <button key={s.id} className="press v-chip" onClick={() => onSelect(s.id)}>{t(s)}</button>
            ))}
          </div>
          {/* keyboard input option */}
          <button className="press v-btn-ghost" style={{ marginTop: 28 }}
            onClick={() => { setKbValue(""); setKbOpen(true); }}>
            <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="7" y1="9" x2="7.01" y2="9"/><line x1="12" y1="9" x2="12.01" y2="9"/><line x1="17" y1="9" x2="17.01" y2="9"/><line x1="7" y1="13" x2="7.01" y2="13"/><line x1="17" y1="13" x2="17.01" y2="13"/><line x1="10" y1="13" x2="14" y2="13"/></svg>
            {t({ vi: "Nhập bằng bàn phím", en: "Type your request" })}
          </button>
        </div>
      )}

      {/* ---- LISTENING phase ---- */}
      {phase === "listening" && (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 0, padding: "0 48px" }}>
          <div style={{ position: "relative", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 48 }}>
            <div className="v-ring v-r1 v-listen" style={{ borderColor: accent + "55" }} />
            <div className="v-ring v-r2 v-listen" style={{ borderColor: accent + "38", animationDelay: ".2s" }} />
            <button className="v-mic-btn v-mic-on" style={{ background: `linear-gradient(145deg, ${accent}, #b55d3e)`, boxShadow: `0 0 0 0 ${accent}88, 0 24px 60px ${accent}66` }}>
              <svg viewBox="0 0 24 24" width="64" height="64" fill="none" stroke="#fff" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                <line x1="12" y1="19" x2="12" y2="23"/>
                <line x1="8" y1="23" x2="16" y2="23"/>
              </svg>
            </button>
          </div>

          <div style={{ color: accent, fontSize: 20, fontWeight: 700, letterSpacing: ".04em", textTransform: "uppercase", marginBottom: 20 }}>
            {t({ vi: "Đang nghe…", en: "Listening…" })}
          </div>

          <Waveform active color={accent} />

          {/* live transcript */}
          <div style={{ marginTop: 36, minHeight: 80, maxWidth: 680, textAlign: "center" }}>
            {transcript && (
              <div style={{ display: "inline-block", background: "rgba(255,255,255,.07)", border: "1px solid rgba(255,255,255,.12)", borderRadius: 20, padding: "18px 30px", fontSize: 24, color: "#fff", fontStyle: "italic", lineHeight: 1.4 }}>
                "{transcript}<span className="v-cursor">|</span>"
              </div>
            )}
          </div>
        </div>
      )}

      {/* ---- PROCESSING phase ---- */}
      {phase === "processing" && (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 32 }}>
          <div style={{ position: "relative", width: 120, height: 120 }}>
            <div className="v-proc-ring" style={{ borderTopColor: accent }} />
            <div style={{ position: "absolute", inset: 0, display: "grid", placeItems: "center" }}>
              <svg viewBox="0 0 24 24" width="44" height="44" fill="none" stroke={accent} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 4l1.6 4.4L18 10l-4.4 1.6L12 16l-1.6-4.4L6 10l4.4-1.6z"/>
                <path d="M18 14l.7 1.9L20.5 16.5l-1.8.7L18 19l-.7-1.8-1.8-.7 1.8-.6z"/>
              </svg>
            </div>
          </div>
          <div style={{ textAlign: "center" }}>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 30, fontWeight: 700, color: "#fff", marginBottom: 8 }}>{t({ vi: "AI đang phân tích…", en: "AI is analysing…" })}</div>
            <div style={{ color: "rgba(255,255,255,.5)", fontSize: 19 }}>{t({ vi: "Hiểu nội dung và tìm thủ tục phù hợp", en: "Understanding intent and matching procedures" })}</div>
          </div>
          {/* transcript replay */}
          <div style={{ background: "rgba(255,255,255,.06)", border: "1px solid rgba(255,255,255,.1)", borderRadius: 16, padding: "16px 28px", fontSize: 20, color: "rgba(255,255,255,.6)", fontStyle: "italic", maxWidth: 640, textAlign: "center" }}>
            "{t(demo.query)}"
          </div>
        </div>
      )}

      {/* ---- RESULT phase ---- */}
      {phase === "result" && (
        <div style={{ flex: 1, overflow: "auto", padding: "32px 44px 44px" }}>
          {/* user bubble */}
          <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 20 }}>
            <div style={{ background: "rgba(255,255,255,.09)", border: "1px solid rgba(255,255,255,.12)", borderRadius: "20px 20px 4px 20px", padding: "16px 22px", maxWidth: "80%", fontSize: 20, color: "rgba(255,255,255,.85)", fontStyle: "italic", lineHeight: 1.4 }}>
              "{t(demo.query)}"
            </div>
          </div>

          {/* AI response bubble */}
          <div style={{ display: "flex", gap: 14, marginBottom: 28 }}>
            <div style={{ width: 50, height: 50, flex: "0 0 50px", borderRadius: "50%", background: `linear-gradient(145deg, ${accent}, #b55d3e)`, display: "grid", placeItems: "center" }}>
              <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#fff" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round"><path d="M12 4l1.6 4.4L18 10l-4.4 1.6L12 16l-1.6-4.4L6 10l4.4-1.6z"/></svg>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ background: "rgba(255,255,255,.08)", border: "1px solid rgba(255,255,255,.12)", borderRadius: "4px 20px 20px 20px", padding: "18px 22px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 10 }}>
                  <span style={{ fontSize: 16, fontWeight: 700, color: accent }}>{t({ vi: "Trợ lý AI", en: "AI Assistant" })}</span>
                  <span style={{ fontSize: 13, color: "rgba(255,255,255,.35)", fontVariantNumeric: "tabular-nums" }}>
                    {t({ vi: "Độ chính xác", en: "Confidence" })}: <b style={{ color: "#4FBE87" }}>{demo.confidence}%</b>
                  </span>
                </div>
                <div style={{ fontSize: 20, color: "rgba(255,255,255,.85)", lineHeight: 1.45 }}>
                  {t({ vi: `Tôi hiểu bạn cần `, en: `I understand you need ` })}
                  <strong style={{ color: "#fff" }}>{t(demo.intent)}</strong>
                  {t({ vi: `. Đây là các thủ tục phù hợp với yêu cầu của bạn:`, en: `. Here are the procedures that match your request:` })}
                </div>
              </div>
            </div>
          </div>

          {/* Service cards */}
          <div style={{ display: "flex", flexDirection: "column", gap: 14, marginBottom: 28 }}>
            {demo.services.map((svc) => (
              <ServiceCard key={svc.id} svc={svc} t={t} onSelect={onSelect} accent={accent} />
            ))}
          </div>

          {/* retry / browse */}
          <div style={{ display: "flex", gap: 14, justifyContent: "center" }}>
            <button className="press v-btn-ghost" onClick={retry}>
              <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.17"/></svg>
              {t({ vi: "Nói lại", en: "Try again" })}
            </button>
            <button className="press v-btn-ghost" onClick={() => { setKbValue(""); setKbOpen(true); }}>
              <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="7" y1="9" x2="7.01" y2="9"/><line x1="12" y1="9" x2="12.01" y2="9"/><line x1="17" y1="9" x2="17.01" y2="9"/><line x1="7" y1="13" x2="7.01" y2="13"/><line x1="17" y1="13" x2="17.01" y2="13"/><line x1="10" y1="13" x2="14" y2="13"/></svg>
              {t({ vi: "Nhập bằng bàn phím", en: "Type instead" })}
            </button>
            <button className="press v-btn-ghost" onClick={() => setPhase("browse")}>
              <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>
              {t({ vi: "Xem tất cả thủ tục", en: "Browse all" })}
            </button>
          </div>
        </div>
      )}

      {/* ---- BROWSE phase ---- */}
      {phase === "browse" && (
        <div style={{ flex: 1, overflow: "auto", padding: "32px 44px 44px" }}>
          <div style={{ fontFamily: "var(--font-display)", fontSize: 36, fontWeight: 700, color: "#fff", marginBottom: 8, letterSpacing: "-.02em" }}>
            {t({ vi: "Chọn thủ tục", en: "Select procedure" })}
          </div>
          <div style={{ fontSize: 19, color: "rgba(255,255,255,.5)", marginBottom: 30 }}>
            {t({ vi: "Chạm vào thủ tục bạn cần thực hiện", en: "Tap the procedure you need" })}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            {ALL_SERVICES.map((s) => (
              <button key={s.id} className="press v-browse-card" onClick={() => onSelect(s.id)}>
                <div style={{ fontFamily: "var(--font-display)", fontSize: 21, fontWeight: 700, color: "#fff", marginBottom: 6, letterSpacing: "-.01em" }}>{t(s)}</div>
                <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 15, color: accent, fontWeight: 600 }}>
                  {t({ vi: "Bắt đầu", en: "Start" })}
                  <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="4" y1="12" x2="19" y2="12"/><polyline points="13 6 19 12 13 18"/></svg>
                </div>
              </button>
            ))}
          </div>
          <button className="press v-btn-ghost" style={{ marginTop: 28, width: "100%", justifyContent: "center" }} onClick={() => setPhase("welcome")}>
            <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/></svg>
            {t({ vi: "Dùng giọng nói", en: "Use voice instead" })}
          </button>
        </div>
      )}
      {KB && (
        <KB
          visible={kbOpen}
          mode="text"
          label={t({ vi: "Nhập câu hỏi hoặc tên thủ tục", en: "Type your question or procedure name" })}
          value={kbValue}
          onChange={(v) => setKbValue(typeof v === "function" ? v(kbValue) : v)}
          onConfirm={handleKbConfirm}
          onClose={() => setKbOpen(false)}
          lang={lang}
        />
      )}
    </div>
  );
}

window.VoiceScreen = VoiceScreen;

