/* ============================================================
   Smart Government Kiosk Platform — Design Tokens
   Apple structural/type language + warm terracotta gov accent.
   ============================================================ */

/* ── SF Pro Display (headings ≥19px) ─────────────────────── */
@font-face { font-family:"SF Pro Display"; font-weight:400; font-style:normal; src:url("fonts/sf-pro-display_regular.woff2") format("woff2"); font-display:swap; }
@font-face { font-family:"SF Pro Display"; font-weight:500; font-style:normal; src:url("fonts/sf-pro-display_medium.woff2") format("woff2"); font-display:swap; }
@font-face { font-family:"SF Pro Display"; font-weight:600; font-style:normal; src:url("fonts/sf-pro-display_semibold.woff2") format("woff2"); font-display:swap; }
@font-face { font-family:"SF Pro Display"; font-weight:700; font-style:normal; src:url("fonts/sf-pro-display_bold.woff2") format("woff2"); font-display:swap; }

/* ── SF Pro Text (body/UI <20px) ─────────────────────────── */
@font-face { font-family:"SF Pro Text"; font-weight:400; font-style:normal; src:url("fonts/sf-pro-text_regular.woff2") format("woff2"); font-display:swap; }
@font-face { font-family:"SF Pro Text"; font-weight:500; font-style:normal; src:url("fonts/sf-pro-text_regular.woff2") format("woff2"); font-display:swap; }
@font-face { font-family:"SF Pro Text"; font-weight:600; font-style:normal; src:url("fonts/sf-pro-text_semibold.woff2") format("woff2"); font-display:swap; }
@font-face { font-family:"SF Pro Text"; font-weight:700; font-style:normal; src:url("fonts/sf-pro-text_semibold.woff2") format("woff2"); font-display:swap; }

:root {
  /* ---- Button / CTA amber (rgb 255,194,81) ---- */
  --cta:          #FFC251;
  --cta-strong:   #E8A820;   /* hover / pressed */
  --cta-deep:     #B8781A;   /* text-on-tint */
  --cta-soft:     #FFF8E8;   /* tint surface */
  --cta-ring:     rgba(255,194,81,0.38);
  --on-cta:       #2A1E08;   /* dark text on amber — 8.7:1 contrast */

  /* ── Brand — warm terracotta (rgb 206,122,88) ──────────── */
  --primary:          #CE7A58;   /* core accent */
  --primary-strong:   #B65F3D;   /* hover / pressed / emphasis */
  --primary-deep:     #93482C;   /* text-on-tint, deep accents */
  --primary-soft:     #FBF1EB;   /* tint surface */
  --primary-soft-2:   #F4DDCF;   /* tint surface, stronger */
  --primary-ring:     rgba(206,122,88,0.32);
  --on-primary:       #ffffff;

  /* ── Neutrals (Apple) ──────────────────────────────────── */
  --canvas:           #ffffff;
  --parchment:        #F6F5F3;   /* warm-tinted off-white */
  --pearl:            #FAFAFB;
  --ink:              #1D1D1F;
  --ink-2:            #44444A;   /* secondary text */
  --ink-3:            #76767E;   /* tertiary / captions */
  --ink-4:            #A6A6AE;   /* disabled / hints */
  --hairline:         #E7E5E2;
  --hairline-strong:  #D8D5D1;
  --surface-dark:     #211F1D;   /* dark panels (debug, code) */
  --surface-dark-2:   #2C2A27;

  /* ── Status ────────────────────────────────────────────── */
  --ok:               #2E9E6B;   --ok-soft:#E6F4EC;
  --warn:             #D98A2B;   --warn-soft:#FBF0DF;
  --err:             #D1574A;    --err-soft:#FBE9E7;
  --info:             #3E7BB6;   --info-soft:#E8F0F7;

  /* ── Type families ─────────────────────────────────────── */
  --font-display: "SF Pro Display","SF Pro Text",system-ui,-apple-system,sans-serif;
  --font-body:    "SF Pro Text",system-ui,-apple-system,sans-serif;

  /* ── Radius (master scale knob, set by Tweaks) ─────────── */
  --r-scale: 1;
  --r-xs:   calc(6px  * var(--r-scale));
  --r-sm:   calc(10px * var(--r-scale));
  --r-md:   calc(14px * var(--r-scale));
  --r-lg:   calc(20px * var(--r-scale));
  --r-xl:   calc(28px * var(--r-scale));
  --r-pill: 9999px;

  /* ── Soft shadows (friendly gov service) ───────────────── */
  --shadow-sm:   0 1px 2px rgba(40,26,16,0.05), 0 2px 6px rgba(40,26,16,0.04);
  --shadow-card: 0 1px 2px rgba(40,26,16,0.05), 0 10px 28px rgba(60,38,22,0.07);
  --shadow-float:0 4px 12px rgba(40,26,16,0.08), 0 20px 48px rgba(60,38,22,0.12);
  --shadow-glow: 0 0 0 4px var(--primary-ring);

  /* ── Spacing (8px base) ────────────────────────────────── */
  --s-1:4px; --s-2:8px; --s-3:12px; --s-4:16px; --s-5:20px; --s-6:24px; --s-8:32px; --s-10:40px; --s-12:48px; --s-16:64px;
}

* { box-sizing:border-box; }
body { margin:0; font-family:var(--font-body); color:var(--ink); -webkit-font-smoothing:antialiased; text-rendering:optimizeLegibility; }
.font-display { font-family:var(--font-display); }

/* Shared press micro-interaction */
.press { transition:transform .12s ease, box-shadow .18s ease, background-color .18s ease, border-color .18s ease; }
.press:active { transform:scale(0.97); }
